package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.junit.jupiter.api.Assumptions.assumeTrue;

import java.io.File;
import java.util.Arrays;

import org.eclipse.rdf4j.benchmark.common.ThemeQueryCatalog;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.repository.util.RDFInserter;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

/**
 * Inner-loop timing sweep for the REAL_ESTATE theme queries: full default-scale dataset in a persistent LMDB store
 * under target/, each query timed with the native engine enabled and disabled. Not a JMH benchmark — this exists to
 * give a fast relative signal between engine changes; rigorous numbers come from ThemeQueryBenchmark under the Docker
 * JFR loop. Enable with -Drdf4j.realestate.timing=true.
 */
public class LmdbRealEstateQueryTimingTest {

	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final int WARMUP = 2;
	private static final int REPS = 5;

	private static SailRepository repository;

	@BeforeAll
	static void setUp() {
		assumeTrue(Boolean.getBoolean("rdf4j.realestate.timing"), "enable with -Drdf4j.realestate.timing=true");
		File storeDir = new File("target", "lmdb-realestate-timing");
		boolean fresh = !new File(storeDir, "triples").exists();
		repository = new SailRepository(new LmdbStore(storeDir, new LmdbStoreConfig("spoc,posc,ospc")));
		if (fresh) {
			long started = System.currentTimeMillis();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin(IsolationLevels.NONE);
				ThemeDataSetGenerator.generate(Theme.REAL_ESTATE, new RDFInserter(connection));
				connection.commit();
			}
			System.out.println("Loaded REAL_ESTATE store in " + (System.currentTimeMillis() - started) + " ms");
		} else {
			System.out.println("Reusing REAL_ESTATE store at " + storeDir);
		}
	}

	@AfterAll
	static void tearDown() {
		if (repository != null) {
			repository.shutDown();
		}
	}

	@Test
	void timeAllQueries() {
		int only = Integer.getInteger("rdf4j.realestate.timing.query", -1);
		int reps = Integer.getInteger("rdf4j.realestate.timing.reps", REPS);
		System.out.println(String.format("%-5s %12s %12s %8s", "query", "native-ms", "generic-ms", "ratio"));
		for (int index = 0; index < ThemeQueryCatalog.QUERY_COUNT; index++) {
			if (only >= 0 && index != only) {
				continue;
			}
			String query = ThemeQueryCatalog.queryFor(Theme.REAL_ESTATE, index);
			// interleave the two modes so page-cache and JIT warmup do not systematically favor
			// whichever mode is measured last
			for (int i = 0; i < WARMUP; i++) {
				timedRun(query, true);
				timedRun(query, false);
			}
			long[] nativeSamples = new long[reps];
			long[] genericSamples = new long[reps];
			long aggCompiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
			for (int i = 0; i < reps; i++) {
				nativeSamples[i] = timedRun(query, true);
				genericSamples[i] = timedRun(query, false);
			}
			boolean nativeAggregate = LmdbNativeAggregateCompiler.COMPILED.get() > aggCompiledBefore;
			double nativeMs = median(nativeSamples);
			double genericMs = median(genericSamples);
			System.out.println(String.format("%-5d %12.2f %12.2f %8.2f %s", index, nativeMs, genericMs,
					genericMs / Math.max(nativeMs, 0.001), nativeAggregate ? "AGG-NATIVE" : "-"));
		}
	}

	private long timedRun(String query, boolean nativeEnabled) {
		String previous = System.getProperty(NATIVE_FLAG);
		try {
			System.setProperty(NATIVE_FLAG, Boolean.toString(nativeEnabled));
			long started = System.nanoTime();
			consume(query);
			return System.nanoTime() - started;
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
	}

	private static double median(long[] samples) {
		Arrays.sort(samples);
		return samples[samples.length / 2] / 1_000_000.0;
	}

	private void consume(String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
				long count = 0;
				while (result.hasNext()) {
					result.next();
					count++;
				}
				if (count < 0) {
					throw new IllegalStateException();
				}
			}
		}
	}
}
